import java.util.*;class Player{static int[]sx=new int[99],sy=new int[99];static int n,lz0,lz1,lzy;static double gy(int lx){for(int i=0;i<n-1;i++)if(lx>=sx[i]&&(lx<sx[i+1]||i==n-2))return sy[i]+(double)(sy[i+1]-sy[i])*(lx-sx[i])/(sx[i+1]-sx[i]);return sy[n-1];}public static void main(String[]a){var s=new Scanner(System.in);n=s.nextInt();for(int i=0;i<n;i++){sx[i]=s.nextInt();sy[i]=s.nextInt();}for(int i=0;i<n-1;i++)if(sy[i]==sy[i+1]&&sx[i+1]-sx[i]>=1000){lz0=sx[i];lz1=sx[i+1];lzy=sy[i];break;}for(;;){int X=s.nextInt(),Y=s.nextInt(),hs=s.nextInt(),vs=s.nextInt(),fu=s.nextInt(),ro=s.nextInt(),pw=s.nextInt();double tx=(lz0+lz1)/2.0,dg=Y-gy(X),df=Y-lzy;int tr=0,tp=0;if(dg<150&&vs<-20){tr=0;tp=4;}else if(Y>300&&(Math.abs(hs)>25||X<lz0||X>lz1)){if(hs>60)tr=90;else if(hs<-60)tr=-90;else if(X<lz0&&hs<10)tr=-45;else if(X>lz1&&hs>-10)tr=45;else if(Math.abs(hs)>20)tr=hs>0?30:-30;else tr=X<tx-100?-10:X>tx+100?10:0;tp=4;}else if(df<300&&X>=lz0&&X<=lz1&&Math.abs(hs)<=25){tr=0;tp=vs<-40?4:vs<-20?3:vs<-10?2:0;}else{tr=Math.abs(hs)>5?(hs>0?10:-10):X<tx-50?-5:X>tx+50?5:0;tp=tr!=0?4:vs<-35?4:vs>-20?0:3;}int dr=Math.max(-90,Math.min(90,tr));dr=Math.max(ro-15,Math.min(ro+15,dr));int dp=Math.max(0,Math.min(4,tp));dp=Math.max(pw-1,Math.min(pw+1,dp));System.out.println(dr+" "+dp);System.out.flush();}}}